import sys
sys.stdin = open("input.txt", "r")
sys.stdout = open("output.txt", "w")
input = sys.stdin.readline

class Solution:
    def solve(self, nums):
        n = len(nums)
        for i in range(n):
            swapped = False
            for j in range(n - i - 1):
                if nums[j] > nums[j + 1]:
                    swapped = True
                    nums[j], nums[j + 1] = nums[j + 1], nums[j]
            if not swapped:
                break
        return nums == sorted(nums) or nums == sorted(nums, reverse=True)

solution = Solution()
output = solution.solve(list(map(int, input().split())))
print("\n" if output else "\n")

